class FreqStack {
    Map<Integer, Integer> freq;
    Stack<Integer> stack;
    Stack<Integer> minFreqStack;
    public FreqStack() {
        freq = new HashMap<>();
        stack = new Stack<>();
        minFreqStack = new Stack<>();
    }

    public void push(int val) {
        freq.put(val, freq.getOrDefault(val, 0) + 1);
        stack.push(val);
        while (!minFreqStack.isEmpty() && freq.get(minFreqStack.peek()) <= freq.get(val)) {
            minFreqStack.pop();
        }
        minFreqStack.push(val);
    }

    public int pop() {
        int val = stack.pop();
        freq.put(val, freq.get(val) - 1);
        return val;
    }
}
